const nome = $input.first().json.input?.nome || $input.first().json.nome || '';
const url = 'https://chinelarialeilaneneves.painel.magazord.com.br/api/v2/site/produto';
const auth = Buffer.from('MZDKc9317ea99f7807c12d38f598bd271aee5cc82c80abe23c3c95ae5465104c:u@DlO9bYoZ7$').toString('base64');

const response = await fetch(`${url}?nome=${encodeURIComponent(nome)}&limit=10`, {
  headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/json' }
});
const data = await response.json();

if (data.status === 'success' && data.data?.items) {
  const produtos = data.data.items.map(p => ({
    nome: p.nome,
    codigo: p.codigo,
    marca_id: p.marca,
    ativo: p.ativo,
    derivacoes: (p.derivacoes || []).filter(d => typeof d === 'object').map(d => d.nome).slice(0, 5)
  }));
  return JSON.stringify({ total: data.data.items.length, produtos });
}
return JSON.stringify({ erro: 'Nenhum produto encontrado', resposta: data });

