const produtoPai = $input.first().json.input?.produtoPai || $input.first().json.produtoPai || '';
const url = 'https://chinelarialeilaneneves.painel.magazord.com.br/api/v1/listEstoque';
const auth = Buffer.from('MZDKc9317ea99f7807c12d38f598bd271aee5cc82c80abe23c3c95ae5465104c:u@DlO9bYoZ7$').toString('base64');

const response = await fetch(`${url}?produtoPai=${encodeURIComponent(produtoPai)}&ativo=true&limit=100`, {
  headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/json' }
});
const data = await response.json();

if (data.data && Array.isArray(data.data)) {
  const estoque = data.data
    .filter(item => item.quantidadeDisponivelVenda > 0)
    .map(item => ({
      descricao: item.descricaoProduto,
      quantidade: item.quantidadeDisponivelVenda,
      sku: item.produto
    }));
  const semEstoque = data.data.filter(item => item.quantidadeDisponivelVenda === 0).length;
  return JSON.stringify({ com_estoque: estoque.length, sem_estoque: semEstoque, itens: estoque });
}
return JSON.stringify({ erro: 'Não foi possível consultar estoque', resposta: data });

