const codigoProduto = $input.first().json.input?.codigoProduto || $input.first().json.codigoProduto || '';
const url = `https://chinelarialeilaneneves.painel.magazord.com.br/api/v2/site/produto/${encodeURIComponent(codigoProduto)}`;
const auth = Buffer.from('MZDKc9317ea99f7807c12d38f598bd271aee5cc82c80abe23c3c95ae5465104c:u@DlO9bYoZ7$').toString('base64');

const response = await fetch(url, {
  headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/json' }
});
const data = await response.json();

if (data.status === 'success' && data.data) {
  const p = data.data;
  const info = p.produtoLoja?.[0] || {};
  const descHtml = info.descricao || '';
  const descClean = descHtml.replace(/<[^>]*>/g, ' ').replace(/\s+/g, ' ').trim().substring(0, 500);
  return JSON.stringify({
    nome: p.nome,
    modelo: p.modelo,
    codigo: p.codigo,
    marca_id: p.marca,
    titulo: info.titulo,
    complemento: info.tituloComplemento,
    descricao: descClean,
    acompanha: p.acompanha,
    ativo: p.ativo,
    link_site: `https://www.chinelarialeilaneneves.com.br/${info.titulo ? info.titulo.toLowerCase().replace(/[^a-z0-9]+/g, '-') : codigoProduto}`
  });
}
return JSON.stringify({ erro: 'Produto não encontrado', resposta: data });

