const termo = $input.first().json.input?.termo || $input.first().json.termo || '';
const url = 'https://chinelarialeilaneneves.painel.magazord.com.br/api/v3/produtos/query?limit=15';
const auth = Buffer.from('MZDKc9317ea99f7807c12d38f598bd271aee5cc82c80abe23c3c95ae5465104c:u@DlO9bYoZ7$').toString('base64');

const response = await fetch(url, {
  method: 'POST',
  headers: { 'Authorization': `Basic ${auth}`, 'Content-Type': 'application/json' },
  body: JSON.stringify({ filters: [{ field: 'nomeDerivacao', operator: 'like', value: termo }] })
});
const data = await response.json();

if (data.items && Array.isArray(data.items)) {
  const produtos = data.items.map(item => ({
    nome: item.nomeProduto,
    derivacao: item.nomeDerivacao,
    codigo: item.codigoProduto,
    sku: item.derivacaoCodigo,
    marca: item.nomeMarca,
    ativo: item.ativo
  }));
  return JSON.stringify({ total: data.total, encontrados: produtos.length, produtos });
}
return JSON.stringify({ erro: 'Nenhum produto encontrado', resposta: data });

